import { Component, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { SeedService } from '../../../data/seed.service';
import { AuthService } from '../../../core/services/auth.service';
import { Order } from '../../../data/models';

interface Milestone {
  label: string;
  detail: string;
  done: boolean;
}

@Component({
  selector: 'app-portal-order-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './portal-order-detail.component.html',
  styleUrl: './portal-order-detail.component.css',
})
export class PortalOrderDetailComponent {
  private route = inject(ActivatedRoute);
  order: Order | undefined;

  constructor(public seed: SeedService, public auth: AuthService) {
    const id = this.route.snapshot.paramMap.get('id');
    const found = id ? this.seed.orderById(id) : undefined;
    // STRICT company scoping — only surface the order if it belongs to QES.
    this.order = found && found.accountName.includes('QES') ? found : undefined;
  }

  statusBadge(status: Order['status']): string {
    switch (status) {
      case 'confirmed': return 'badge-info';
      case 'in-production': return 'badge-warning';
      case 'shipped': return 'badge-success';
      case 'delivered': return 'badge-neutral';
      default: return 'badge-neutral';
    }
  }

  // Read-only illustrative milestone timeline derived from the order status.
  milestones(o: Order): Milestone[] {
    const order: Order['status'][] = ['confirmed', 'in-production', 'shipped', 'delivered'];
    const idx = order.indexOf(o.status);
    return [
      { label: 'Order confirmed', detail: `PO ${o.poNumber} accepted`, done: idx >= 0 },
      { label: 'In production', detail: `Lead time ~${o.leadTimeWeeks} weeks`, done: idx >= 1 },
      { label: 'Shipped', detail: `Scheduled ship date ${o.ssd}`, done: idx >= 2 },
      { label: 'Delivered', detail: `Requested delivery ${o.rdd}`, done: idx >= 3 },
    ];
  }
}
